import xml.etree.ElementTree as ET
import pandas as pd

# read file
tree = ET.parse("/home/ssr/Downloads/all_india_toll_plazas.kml")
root = tree.getroot()

# KML namespace
ns = {"k": "http://www.opengis.net/kml/2.2"}

rows = []

for pm in root.findall(".//k:Placemark", ns):

    row = {}
    for sd in pm.findall(".//k:SimpleData", ns):
        name = sd.attrib.get("name")
        value = sd.text

        if name in [
            "plaza_code",
            "plaza_name",
            "plaza_type",
            "plaza_sub_type",
            "address",
            "location",
            "lat",
            "long",
            "concessionaire_name",
            "concessionaire_type",
            "city",
            "state",
        ]:
            row[name] = value

    if row:    # only append if any match
        rows.append(row)

df = pd.DataFrame(rows)

# sort by state, city
df = df.sort_values(by=["state", "city", "plaza_code"])

